 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 5	import { MenuItem } from '@patternfly/react-core';
 6	
 7	import { InstanceTypeSize } from '../../utils/types';
 8	
 9	type RedHatInstanceTypeSeriesSizesMenuItemProps = {
10	  selected: string;
11	  seriesName: string;
12	  setSelected: Dispatch<SetStateAction<string>>;
13	  sizes: InstanceTypeSize[];
14	};
15	
16	const RedHatInstanceTypeSeriesSizesMenuItems: FC<RedHatInstanceTypeSeriesSizesMenuItemProps> = ({
17	  selected,
18	  seriesName,
19	  setSelected,
20	  sizes,
21	}) => {
22	  const { t } = useKubevirtTranslation();
23	
24	  return (
25	    <>
26	      {sizes.map(({ cpus, memory, sizeLabel }) => {
27	        const itName = `${seriesName}.${sizeLabel}`;
28	        const itLabel = t('{{sizeLabel}}: {{cpus}} CPUs, {{memory}} Memory', {
29	          cpus,
30	          memory: readableSizeUnit(memory),
31	          sizeLabel,
32	        });
33	        return (
34	          <MenuItem
35	            isSelected={selected === itName}
36	            itemId={itName}
37	            key={itName}
38	            onClick={() => setSelected(itName)}
39	          >
40	            {itLabel}
41	          </MenuItem>
42	        );
43	      })}
44	    </>
45	  );
46	};
47	
48	export default RedHatInstanceTypeSeriesSizesMenuItems;

